function getAllProjects() {
    try {
        // Cleanup old keys
        for (let i = localStorage.length - 1; i >= 0; i--) {
            let k = localStorage.key(i);
            if (k && k.startsWith('sandeep_projects_') && k !== 'sandeep_projects_v25') {
                localStorage.removeItem(k);
              }
              if (k === 'sandeep_versions') {
                  localStorage.removeItem(k);
            }
        }
        const raw = localStorage.getItem('sandeep_projects_v25');
        if (raw === null) {
            try { localStorage.setItem('sandeep_projects_v25', JSON.stringify(DEFAULT_PROJECTS)); } catch(e){}
            return DEFAULT_PROJECTS;
        }
        let projects = JSON.parse(raw);
        
        // Self-healing: inject missing projects and merge missing images/banners
        let updated = false;
        for (const dp of DEFAULT_PROJECTS) {
            let existing = projects.find(p => p && p.id === dp.id);
            if (!existing) {
                projects.push(dp);
                updated = true;
            } else {
                // Do not override user's custom images or banner even if length differs.
            }
        }
        // Self-healing deduplication by ID
        const unique = [];
        const seen = new Set();
        for (const p of projects) {
            if (p && p.id && !seen.has(p.id)) {
                seen.add(p.id);
                unique.push(p);
            }
        }
        if (unique.length !== projects.length || updated) {
            try { localStorage.setItem('sandeep_projects_v25', JSON.stringify(unique)); } catch(e){}
        }
        return unique;
    } catch {
        return DEFAULT_PROJECTS;
    }
}

window.getAllProjects = getAllProjects;




















